import{_ as a,b as e,e as i,al as n}from"./chunks/framework.DrQIcdFj.js";(function(){try{var t=typeof window<"u"?window:typeof global<"u"?global:typeof globalThis<"u"?globalThis:typeof self<"u"?self:{};t.SENTRY_RELEASE={id:"abf23ae41d8e9798d1084c6d3fd2516340828177"};var o=new t.Error().stack;o&&(t._sentryDebugIds=t._sentryDebugIds||{},t._sentryDebugIds[o]="2d3718ce-2435-4b85-9a02-65389b82f572",t._sentryDebugIdIdentifier="sentry-dbid-2d3718ce-2435-4b85-9a02-65389b82f572")}catch{}})();const l="/CoreFront-EndConcepts/img/ip.png",I=JSON.parse('{"title":"IP 协议","description":"","frontmatter":{},"headers":[],"relativePath":"networkAndBrowsers/protocols/ip.md","filePath":"networkAndBrowsers/protocols/ip.md","lastUpdated":null}'),s={name:"networkAndBrowsers/protocols/ip.md"};function d(t,o,r,P,g,h){return e(),i("div",null,[...o[0]||(o[0]=[n('<h1 id="ip-协议" tabindex="-1">IP 协议 <a class="header-anchor" href="#ip-协议" aria-label="Permalink to &quot;IP 协议&quot;">​</a></h1><h2 id="_1-什么是-ip-协议" tabindex="-1">1. 什么是 IP 协议？ <a class="header-anchor" href="#_1-什么是-ip-协议" aria-label="Permalink to &quot;1. 什么是 IP 协议？&quot;">​</a></h2><p><strong>IP</strong> (Internet Protocol，互联网协议) 是整个 TCP/IP 协议族中<strong>最核心的协议之一</strong>。在 OSI 模型中，它位于第三层（<strong>网络层</strong>），向下承接数据链路层（如以太网、Wi-Fi），向上服务于传输层（如 TCP、UDP）。</p><p>如果说 TCP 是负责把包裹打包并保证完好无损的“快递总管”，那么 <strong>IP 协议就是整个“国家邮政系统”及其内部的“分拣转运规则”</strong>。它的唯一使命是：<strong>将数据包从源主机，跨越多个网络（路由器），尽力送达到目标主机。</strong></p><h2 id="_2-ip-协议的核心特征" tabindex="-1">2. IP 协议的核心特征 <a class="header-anchor" href="#_2-ip-协议的核心特征" aria-label="Permalink to &quot;2. IP 协议的核心特征&quot;">​</a></h2><p>IP 协议的设计理念非常纯粹，可以用三个词概括：</p><ul><li><strong>无连接 (Connectionless)：</strong> 发送数据之前，源主机和目标主机之间不需要建立任何连接。每个 IP 数据包（也叫数据报）都是独立的，它们可能走不同的物理路径到达目的地。</li><li><strong>不可靠 (Unreliable)：</strong> IP 协议<strong>不保证</strong>数据包一定能送达。如果途中遇到路由器拥堵、线路故障或数据校验错误，IP 协议会直接丢弃该数据包，且<strong>不会</strong>通知发送方。可靠性（如重传机制）完全交由上层的 TCP 协议来保障。</li><li><strong>尽力而为 (Best-Effort Delivery)：</strong> 虽然不可靠，但 IP 协议绝不偷懒。它会尽最大努力把数据包传输出去，不到万不得已绝不丢弃。</li></ul><h2 id="_3-ip-地址体系-ipv4-与-ipv6" tabindex="-1">3. IP 地址体系 (IPv4 与 IPv6) <a class="header-anchor" href="#_3-ip-地址体系-ipv4-与-ipv6" aria-label="Permalink to &quot;3. IP 地址体系 (IPv4 与 IPv6)&quot;">​</a></h2><p>要实现全网通信，必须给网络上的每一个设备分配一个唯一的“家庭住址”，这就是 IP 地址。</p><h3 id="_3-1-ipv4-目前的绝对主流" tabindex="-1">3.1 IPv4 (目前的绝对主流) <a class="header-anchor" href="#_3-1-ipv4-目前的绝对主流" aria-label="Permalink to &quot;3.1 IPv4 (目前的绝对主流)&quot;">​</a></h3><ul><li><strong>格式：</strong> 由 32 位二进制数组成，通常写成 4 段十进制数字（点分十进制），例如：<code>192.168.1.1</code>。</li><li><strong>容量危机：</strong> 32 位地址理论上最多只能提供约 43 亿个地址。随着移动互联网和物联网的爆发，IPv4 地址早在 2011 年就已分配殆尽。（目前主要靠 NAT 技术——让一个局域网共用一个公网 IP 来续命）。</li></ul><h3 id="_3-2-ipv6-未来的必然趋势" tabindex="-1">3.2 IPv6 (未来的必然趋势) <a class="header-anchor" href="#_3-2-ipv6-未来的必然趋势" aria-label="Permalink to &quot;3.2 IPv6 (未来的必然趋势)&quot;">​</a></h3><ul><li><strong>格式：</strong> 由 128 位二进制数组成，通常写成 8 段十六进制数字，例如：<code>2001:0db8:85a3:0000:0000:8a2e:0370:7334</code>。</li><li><strong>容量恐怖：</strong> 它的地址数量多到“可以给地球上的每一粒沙子都分配一个 IP 地址”，彻底解决了地址枯竭问题，并自带更高的安全性（内置 IPsec）。</li></ul><table tabindex="0"><thead><tr><th>维度</th><th>IPv4</th><th>IPv6</th></tr></thead><tbody><tr><td><strong>地址长度</strong></td><td>32 bits (4 字节)</td><td>128 bits (16 字节)</td></tr><tr><td><strong>地址数量</strong></td><td>约 43 亿个</td><td>极其庞大 ($2^{128}$ 个)</td></tr><tr><td><strong>表示方法</strong></td><td>点分十进制 (如 192.168.0.1)</td><td>冒号十六进制 (如 fe80::1)</td></tr><tr><td><strong>报文头部</strong></td><td>长度可变 (20-60 字节)，有校验和</td><td>长度固定 (40 字节)，去除校验和，处理更快</td></tr></tbody></table><h2 id="_4-ip-报文头部的核心字段" tabindex="-1">4. IP 报文头部的核心字段 <a class="header-anchor" href="#_4-ip-报文头部的核心字段" aria-label="Permalink to &quot;4. IP 报文头部的核心字段&quot;">​</a></h2><p>当上层的 TCP 或 UDP 数据来到网络层时，IP 协议会给它套上一个 IP 头部，打包成 IP 数据报。</p><ul><li><strong>版本号 (Version)：</strong> 占 4 位，表明这是 IPv4 还是 IPv6。</li><li><strong>源 IP 地址 (Source Address)：</strong> 占 32 位，表明“包裹是谁寄出的”。</li><li><strong>目的 IP 地址 (Destination Address)：</strong> 占 32 位，表明“包裹要寄给谁”。</li><li><strong>协议 (Protocol)：</strong> 占 8 位，告诉目标主机的网络层，这个包裹拆开后应该交给上面的谁（如果是 <code>6</code> 代表交由 TCP 处理，如果是 <code>17</code> 代表交由 UDP 处理）。</li><li><strong>生存时间 (TTL, Time To Live)：</strong> 占 8 位。这是一个<strong>防死循环的神器</strong>。数据包每经过一个路由器，TTL 的值就减 1。当 TTL 减为 0 时，路由器会直接丢弃该包。这防止了数据包在网络故障时永远在几个路由器之间转圈圈。</li></ul><h2 id="_5-ip-路由-包裹是如何跨越全球的" tabindex="-1">5. IP 路由：包裹是如何跨越全球的？ <a class="header-anchor" href="#_5-ip-路由-包裹是如何跨越全球的" aria-label="Permalink to &quot;5. IP 路由：包裹是如何跨越全球的？&quot;">​</a></h2><p>IP 协议最核心的能力就是<strong>路由寻址（Routing）</strong>。</p><p>当你在北京给纽约的服务器发送一个 IP 数据包时，它并不知道一条完整的直达路线。它采用的是“接力赛（Hop-by-Hop）”模式：</p><ul><li>你的电脑检查目标 IP 发现不在同一个局域网，于是把包交给家里的路由器（默认网关）。</li><li>家里路由器拆开包看一下目标 IP，查一下自己的<strong>路由表</strong>，发现应该交给运营商的骨干路由器。</li><li>骨干路由器再查路由表，交给海底光缆的节点路由器...</li><li>就这样，数据包在途中经历十几次甚至几十次“问路（查询路由表）和转发（跳跃 Hop）”，最终抵达纽约的服务器。</li></ul><blockquote><p><strong>核心逻辑：</strong> 每一台路由器都不需要知道去纽约的完整路线，它只需要知道“下一步该把包扔给谁离纽约更近”即可。</p></blockquote><h2 id="_6-完整流程图" tabindex="-1">6. 完整流程图 <a class="header-anchor" href="#_6-完整流程图" aria-label="Permalink to &quot;6. 完整流程图&quot;">​</a></h2><p><img src="'+l+'" alt="Logo" data-zoomable="true"></p><h2 id="_7-常见问题-faq" tabindex="-1">7. 常见问题 (FAQ) <a class="header-anchor" href="#_7-常见问题-faq" aria-label="Permalink to &quot;7. 常见问题 (FAQ)&quot;">​</a></h2><h3 id="_7-1-ip-协议既然不可靠-为什么还要用它" tabindex="-1">7.1 IP 协议既然不可靠，为什么还要用它？ <a class="header-anchor" href="#_7-1-ip-协议既然不可靠-为什么还要用它" aria-label="Permalink to &quot;7.1 IP 协议既然不可靠，为什么还要用它？&quot;">​</a></h3><ul><li><strong>答：为了效率和灵活性。</strong> 网络层的任务就是快速转发数据。如果把重传、排序等复杂逻辑都放在这一层，路由器的负担会太重，导致全网变慢。复杂的逻辑交给端点（主机）的 TCP 层去处理，实现了“简单网络，复杂终端”的优秀设计理念。</li></ul><h3 id="_7-2-ip-地址和-mac-地址有什么区别" tabindex="-1">7.2 IP 地址和 MAC 地址有什么区别？ <a class="header-anchor" href="#_7-2-ip-地址和-mac-地址有什么区别" aria-label="Permalink to &quot;7.2 IP 地址和 MAC 地址有什么区别？&quot;">​</a></h3><ul><li><strong>IP 地址 (逻辑地址)</strong>：像你的“收货地址”（如 某省某市某街道）。它是动态分配的，决定了你在网络中的逻辑位置，用于跨网络定位。</li><li><strong>MAC 地址 (物理地址)</strong>：像你的“身份证号”。它是固化在网卡里的，全球唯一。它负责在<strong>同一个局域网</strong>内找到对应的硬件设备。</li></ul><h3 id="_7-3-什么是私有-ip-和公有-ip" tabindex="-1">7.3 什么是私有 IP 和公有 IP？ <a class="header-anchor" href="#_7-3-什么是私有-ip-和公有-ip" aria-label="Permalink to &quot;7.3 什么是私有 IP 和公有 IP？&quot;">​</a></h3><ul><li><strong>公有 IP</strong>：全球唯一，可以直接在互联网上被访问。</li><li><strong>私有 IP</strong>：用于家庭、公司内部局域网（如 <code>192.168.x.x</code>）。它们在互联网上不可见。通过 <strong>NAT (网络地址转换)</strong> 技术，多个私有 IP 可以共享一个公有 IP 来上网。</li></ul><h3 id="_7-4-什么是静态-ip-和动态-ip" tabindex="-1">7.4 什么是静态 IP 和动态 IP？ <a class="header-anchor" href="#_7-4-什么是静态-ip-和动态-ip" aria-label="Permalink to &quot;7.4 什么是静态 IP 和动态 IP？&quot;">​</a></h3><ul><li><strong>静态 IP</strong>：固定不变的地址，通常给服务器使用，方便别人访问。</li><li><strong>动态 IP</strong>：每次上网时通过 <strong>DHCP 协议</strong> 临时分配的地址，资源利用率更高，适合普通家用电脑和手机。</li></ul><h3 id="_7-5-如果-ttl-设得太小会怎样" tabindex="-1">7.5 如果 TTL 设得太小会怎样？ <a class="header-anchor" href="#_7-5-如果-ttl-设得太小会怎样" aria-label="Permalink to &quot;7.5 如果 TTL 设得太小会怎样？&quot;">​</a></h3><ul><li>数据包可能还没到达目的地，就在半路因为 TTL 耗尽而被路由器丢弃。你会收到一个 <strong>ICMP Time Exceeded</strong> 的报错信息。</li></ul>',35)])])}const c=a(s,[["render",d]]);export{I as __pageData,c as default};
